import{_ as i,n as t,p as n,a2 as a}from"./framework-c4fdf794.js";const s={};function d(l,e){return t(),n("div",null,[...e[0]||(e[0]=[a(`<h1 id="update-guide" tabindex="-1"><a class="header-anchor" href="#update-guide" aria-hidden="true">#</a> Update Guide</h1><div class="tip custom-block"><p class="custom-block-title">Note</p><p>Updates are unconditionally enabled and the Imunify360 service starts during the package update.</p></div><h2 id="gradual-roll-out" tabindex="-1"><a class="header-anchor" href="#gradual-roll-out" aria-hidden="true">#</a> Gradual roll-out</h2><p>New stable Imunify360 versions are scheduled for the gradual roll-out from our production repository and are available for all customers in about two weeks or less from the release.</p><p>If you do not want to wait for the gradual roll-out, you can update Imunify360 to the latest version by running the following commands:</p><div class="notranslate"><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>wget -O imunify-force-update.sh https://repo.imunify360.cloudlinux.com/defence360/imunify-force-update.sh
bash imunify-force-update.sh
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div></div><h2 id="beta" tabindex="-1"><a class="header-anchor" href="#beta" aria-hidden="true">#</a> Beta</h2><p>To upgrade Imunify360 on CentOS/CloudLinux/AlmaLinux systems, run the command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>yum update imunify360-firewall --enablerepo=imunify360-testing
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>To upgrade Imunify360 on Ubuntu 16.04, run the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>echo &#39;deb https://repo.imunify360.cloudlinux.com/imunify360/ubuntu-testing/16.04/ xenial main&#39; &gt; /etc/apt/sources.list.d/imunify360-testing.list
apt-get update
apt-get install --only-upgrade imunify360-firewall
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>To upgrade Imunify360 on Ubuntu 18.04, run the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>echo &#39;deb https://repo.imunify360.cloudlinux.com/imunify360/ubuntu-testing/18.04/ bionic main&#39; &gt; /etc/apt/sources.list.d/imunify360-testing.list
apt-get update
apt-get install --only-upgrade imunify360-firewall
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>To upgrade Imunify360 on Ubuntu 20.04, run the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>echo &#39;deb https://repo.imunify360.cloudlinux.com/imunify360/ubuntu-testing/20.04/ focal main&#39; &gt; /etc/apt/sources.list.d/imunify360-testing.list
apt-get update
apt-get install --only-upgrade imunify360-firewall
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>To upgrade Imunify360 on Ubuntu 22.04, run the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>echo &#39;deb https://repo.imunify360.cloudlinux.com/imunify360/ubuntu-testing/22.04/ jammy main&#39; &gt; /etc/apt/sources.list.d/imunify360-testing.list
apt-get update
apt-get install --only-upgrade imunify360-firewall
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>To upgrade Imunify360 on Ubuntu 24.04, run the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>echo &#39;deb https://repo.imunify360.cloudlinux.com/imunify360/ubuntu-testing/24.04/ noble main&#39; &gt; /etc/apt/sources.list.d/imunify360-testing.list
apt-get update
apt-get install --only-upgrade imunify360-firewall
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>To upgrade Imunify360 on Ubuntu 26.04, run the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>echo &#39;deb https://repo.imunify360.cloudlinux.com/imunify360/ubuntu-testing/26.04/ resolute main&#39; &gt; /etc/apt/sources.list.d/imunify360-testing.list
apt-get update
apt-get install --only-upgrade imunify360-firewall
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>To upgrade Imunify360 on Debian 9 (supported up to Imunify v6.11 (including)), run the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>echo &#39;deb https://repo.imunify360.cloudlinux.com/imunify360/debian-testing/9/ stretch main&#39;  &gt; /etc/apt/sources.list.d/imunify360-testing.list
apt-get update
apt-get install --only-upgrade imunify360-firewall
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>To upgrade Imunify360 on Debian 10, run the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>echo &#39;deb https://repo.imunify360.cloudlinux.com/imunify360/debian-testing/10/ buster main&#39;  &gt; /etc/apt/sources.list.d/imunify360-testing.list
apt-get update
apt-get install --only-upgrade imunify360-firewall
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>To upgrade Imunify360 on Debian 11, run the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>echo &#39;deb https://repo.imunify360.cloudlinux.com/imunify360/debian-testing/11/ bullseye main&#39; &gt; /etc/apt/sources.list.d/imunify360-testing.list
apt-get update
apt-get install --only-upgrade imunify360-firewall
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>To upgrade Imunify360 on Debian 12, run the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>echo &#39;deb https://repo.imunify360.cloudlinux.com/imunify360/debian-testing/12/ bookworm main&#39; &gt; /etc/apt/sources.list.d/imunify360-testing.list
apt-get update
apt-get install --only-upgrade imunify360-firewall
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>To upgrade Imunify360 on Debian 13, run the following command:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>echo &#39;deb https://repo.imunify360.cloudlinux.com/imunify360/debian-testing/13/ trixie main&#39; &gt; /etc/apt/sources.list.d/imunify360-testing.list
apt-get update
apt-get install --only-upgrade imunify360-firewall
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="production" tabindex="-1"><a class="header-anchor" href="#production" aria-hidden="true">#</a> Production</h2><p>CentOS/CloudLinux/AlmaLinux systems:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>yum update imunify360-firewall
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>Ubuntu 16.04, 18.04, 20.04, and 22* systems:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>apt-get update
apt-get install --only-upgrade imunify360-firewall
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><div class="tip custom-block"><p class="custom-block-title">Note</p><p>If you have upgraded the underlying OS (for example, Ubuntu 22.04 → 24.04), the Imunify repository <code>.list</code> files still point at the previous OS version and <code>apt-get update</code> will fail. Run the deploy script with <code>--post-os-upgrade</code> to refresh the repositories — see <a href="#host-os-upgrade">Host OS upgrade</a> below.</p></div><p>Debian 9 (supported up to Imunify v6.11 (including)), 10, and 11 systems:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>apt-get update
apt-get install --only-upgrade imunify360-firewall
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="host-os-upgrade" tabindex="-1"><a class="header-anchor" href="#host-os-upgrade" aria-hidden="true">#</a> Host OS upgrade</h2><p>When you upgrade the underlying operating system (for example, Ubuntu 22.04 → 24.04) on a server where Imunify360 or ImunifyAV is installed, the APT repository <code>.list</code> files keep pointing at the <strong>previous</strong> OS version. As a result <code>apt-get update</code> will either return 404 errors or pull packages built for the old OS, and the daily update cron will silently install the wrong packages.</p><p>This applies only to <strong>Debian/Ubuntu</strong> systems. RPM-based systems (CentOS / CloudLinux / AlmaLinux) are unaffected because <code>yum</code>/<code>dnf</code> resolve the OS version dynamically.</p><p>To recover after a host OS upgrade, run the deploy script with the <code>--post-os-upgrade</code> flag.</p><p>For Imunify360:</p><div class="notranslate"><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>bash i360deploy.sh --post-os-upgrade -y
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></div><p>For ImunifyAV:</p><div class="notranslate"><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>bash imav-deploy.sh --post-os-upgrade -y
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></div><p>The flag requires deploy script version <strong>2.152</strong> or later. It performs the following steps automatically:</p><ol><li>Reinstalls <code>imunify-release</code> for the OS currently reported by <code>/etc/os-release</code>, which rewrites the repository <code>.list</code> files to the new OS version.</li><li>Handles the GPG key <code>.dpkg-dist</code> edge case introduced by Ubuntu 24.04 and later.</li><li>Re-enables the beta/testing repository if it was active before the upgrade.</li><li>Runs <code>apt-get update</code> and reinstalls the product package to pick up binaries built for the new OS.</li><li>Restarts the Imunify service so that the in-memory cache of <code>/etc/os-release</code> is refreshed.</li></ol><div class="tip custom-block"><p class="custom-block-title">Note</p><p>Run <code>--post-os-upgrade</code> only <strong>after</strong> the host OS upgrade has completed and the new OS has booted. The flag is intended for recovery; it cannot be combined with <code>--uninstall</code>. On RPM-based systems the flag exits early with an informational message.</p></div>`,50)])])}const r=i(s,[["render",d],["__file","index.html.vue"]]);export{r as default};
